using System.Collections;
using UnityEngine;

/// <summary>
/// Feedback audiovisual de um inimigo (Enemy Creator — Etapa 7.1): sons,
/// partículas/VFX e ícones de "?"/"!" acima da cabeça.
///
/// Liga-se aos eventos já existentes:
/// - EnemyDetection (Etapa 1.4): OnPlayerSuspicious (ícone "?"),
///   OnPlayerSpotted (ícone "!" + som de detectar + VFX), OnPlayerLost
///   (som de voltar ao normal).
/// - EnemyController.OnStateChanged: carregar (PreparandoAtaque), atacar
///   (Atacando), morrer (Morto), desactivar (Desactivado).
/// - EnemyHealth.OnDamaged: som de tomar dano. O "pisca" ao tomar dano já é
///   feito por EnemyHealth (stats.flashOnHit + flashColor/flashInterval).
///
/// O som de "disparar" de projécteis vem de ProjectileData.fireSound/
/// chargeSound (Etapa 2.2) — não é duplicado aqui.
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
public class EnemyFeedback : MonoBehaviour
{
    [Header("Sons")]
    [Tooltip("Ao confirmar o player (Perseguindo — ícone \"!\").")]
    public AudioClip detectSound;

    [Tooltip("Ao ficar desconfiado (Alerta — ícone \"?\").")]
    public AudioClip suspiciousSound;

    [Tooltip("Ao começar a carregar/preparar um ataque (PreparandoAtaque).")]
    public AudioClip chargeSound;

    [Tooltip("Ao executar um ataque (Atacando).")]
    public AudioClip attackSound;

    [Tooltip("Ao tomar dano (e sobreviver).")]
    public AudioClip hurtSound;

    [Tooltip("Ao morrer (Morto).")]
    public AudioClip deathSound;

    [Tooltip("Ao ser desactivado (Desactivado).")]
    public AudioClip deactivateSound;

    [Tooltip("Ao perder o alvo e voltar ao normal (VoltandoParaCasa).")]
    public AudioClip calmDownSound;

    [Header("Partículas / VFX (prefabs instanciados — opcionais)")]
    [Tooltip("Ao morrer (explosão/fumo).")]
    public GameObject deathVfxPrefab;

    [Tooltip("Ao ser desactivado (faíscas/desligar). Vazio = usa 'deathVfxPrefab'.")]
    public GameObject deactivateVfxPrefab;

    [Tooltip("Ao executar um ataque.")]
    public GameObject attackVfxPrefab;

    [Tooltip("Ao detectar o player (efeito visual de detecção).")]
    public GameObject detectVfxPrefab;

    [Tooltip("ParticleSystem (filho deste inimigo) ligado enquanto anda (Patrulhando/Perseguindo/VoltandoParaCasa) — ex: poeira. Opcional.")]
    public ParticleSystem walkParticles;

    [Header("Ícones (\"?\" / \"!\")")]
    [Tooltip("Prefab do ícone de interrogação (Alerta). Instanciado acima da cabeça.")]
    public GameObject questionIconPrefab;

    [Tooltip("Prefab do ícone de exclamação (Perseguindo).")]
    public GameObject exclamationIconPrefab;

    [Tooltip("Deslocamento do ícone em relação ao inimigo.")]
    public Vector2 iconOffset = new Vector2(0f, 1.2f);

    [Tooltip("Duração (segundos) do ícone antes de desaparecer.")]
    [Min(0.1f)] public float iconDuration = 1f;

    private EnemyController _controller;
    private EnemyDetection _detection;
    private EnemyHealth _health;
    private GameObject _activeIcon;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
        _detection = GetComponent<EnemyDetection>();
        _health = GetComponent<EnemyHealth>();
    }

    private void OnEnable()
    {
        _controller.OnStateChanged += HandleStateChanged;

        if (_detection != null)
        {
            _detection.OnPlayerSuspicious += HandleSuspicious;
            _detection.OnPlayerSpotted += HandleSpotted;
            _detection.OnPlayerLost += HandleLost;
        }

        if (_health != null)
            _health.OnDamaged += HandleDamaged;
    }

    private void OnDisable()
    {
        _controller.OnStateChanged -= HandleStateChanged;

        if (_detection != null)
        {
            _detection.OnPlayerSuspicious -= HandleSuspicious;
            _detection.OnPlayerSpotted -= HandleSpotted;
            _detection.OnPlayerLost -= HandleLost;
        }

        if (_health != null)
            _health.OnDamaged -= HandleDamaged;
    }

    private void Update()
    {
        if (walkParticles == null) return;

        bool moving = !_controller.IsTerminal &&
                      (_controller.State == EnemyState.Patrulhando ||
                       _controller.State == EnemyState.Perseguindo ||
                       _controller.State == EnemyState.VoltandoParaCasa);

        if (moving && !walkParticles.isPlaying) walkParticles.Play();
        else if (!moving && walkParticles.isPlaying) walkParticles.Stop();
    }

    // ==================== Detecção (Etapa 1.4) ====================

    private void HandleSuspicious()
    {
        PlaySound(suspiciousSound);
        ShowIcon(questionIconPrefab);
    }

    private void HandleSpotted()
    {
        PlaySound(detectSound);
        ShowIcon(exclamationIconPrefab);
        SpawnVfx(detectVfxPrefab);
    }

    private void HandleLost()
    {
        PlaySound(calmDownSound);
        HideIcon();
    }

    // ==================== Estados ====================

    private void HandleStateChanged(EnemyState oldState, EnemyState newState)
    {
        switch (newState)
        {
            case EnemyState.PreparandoAtaque:
                PlaySound(chargeSound);
                break;

            case EnemyState.Atacando:
                PlaySound(attackSound);
                SpawnVfx(attackVfxPrefab);
                break;

            case EnemyState.Morto:
                PlaySound(deathSound);
                SpawnVfx(deathVfxPrefab);
                HideIcon();
                break;

            case EnemyState.Desactivado:
                PlaySound(deactivateSound);
                SpawnVfx(deactivateVfxPrefab != null ? deactivateVfxPrefab : deathVfxPrefab);
                HideIcon();
                break;
        }
    }

    private void HandleDamaged(int amount, int currentHealth)
    {
        PlaySound(hurtSound);
    }

    // ==================== Helpers ====================

    private void PlaySound(AudioClip clip)
    {
        if (clip != null) AudioManager.Instance?.PlaySEAtPoint(clip, transform.position);
    }

    private void SpawnVfx(GameObject prefab)
    {
        if (prefab == null) return;
        if (VfxPoolManager.Instance != null) VfxPoolManager.Instance.Spawn(prefab, transform.position);
        else Instantiate(prefab, transform.position, Quaternion.identity);
    }

    private void ShowIcon(GameObject prefab)
    {
        HideIcon();
        if (prefab == null) return;

        _activeIcon = Instantiate(prefab, transform.position + (Vector3)iconOffset, Quaternion.identity, transform);
        StartCoroutine(HideIconAfter(iconDuration));
    }

    private IEnumerator HideIconAfter(float seconds)
    {
        var icon = _activeIcon;
        yield return new WaitForSeconds(seconds);

        if (icon != null && icon == _activeIcon) HideIcon();
    }

    private void HideIcon()
    {
        if (_activeIcon != null)
        {
            Destroy(_activeIcon);
            _activeIcon = null;
        }
    }
}
